// round-start-sound.js — Snake Royale round-start SFX ("...may the odds be ever in your favor")
// Audio embedded as base64 so there is nothing external to host.
(function () {
  const DATA_URI = "data:audio/mpeg;base64,";

  const el = new Audio(DATA_URI);
  el.preload = "auto";
  el.volume = 0.9; // tweak 0.0–1.0 to taste

  // Unlock audio on the first user gesture (browsers block autoplay until then).
  // As the streamer you click the page once and it stays unlocked.
  let unlocked = false;
  function unlock() {
    if (unlocked) return;
    el.play().then(() => { el.pause(); el.currentTime = 0; unlocked = true; })
             .catch(() => {});
    window.removeEventListener("pointerdown", unlock);
    window.removeEventListener("keydown", unlock);
  }
  window.addEventListener("pointerdown", unlock);
  window.addEventListener("keydown", unlock);

  // Call this the moment a round starts.
  window.playRoundStart = function () {
    try { el.currentTime = 0; el.play().catch(() => {}); } catch (e) {}
  };
})();
